try {
    // Set loading state
    variables['d1c4f527-9d4b-4ff5-b8fa-e2d13dbbda25'] = true;

    const stageInfo = context.parameters['stageData'];

    if (!stageInfo || !stageInfo.id) {
      throw new Error('No stage data provided');
    }

    // Prepare update data
    const updateData = {
      stage_name: stageInfo.stage_name,
      description: stageInfo.description,
      estimaed_days: stageInfo.estimaed_days
    };

    // Update stage in Supabase
    const result = await utilsFunctions.executePluginFunction(
      'f9ef41c3-1c53-4857-855b-f2f6a40b7186',
      'update',
      {
        table: 'project-stages',
        mode: 'single',
        primaryData: { id: stageInfo.id },
        data: updateData
      }
    );

    if (result && result.data && result.data.length > 0) {
      // Refresh project stages
      const stagesResult = await utilsFunctions.executePluginFunction(
        'f9ef41c3-1c53-4857-855b-f2f6a40b7186',
        'select',
        {
          table: 'project-stages',
          fieldsMode: 'guided',
          dataFields: ['*'],
          modifiers: {
            order: {
              column: 'stage_number',
              ascending: true
            }
          }
        }
      );

      if (stagesResult) {
        variables['90bf5b2b-db94-4bdf-b415-df005d15a685'] = stagesResult;
      }

      console.log('Project stage updated successfully');
      return { success: true };
    } else {
      throw new Error('Failed to update project stage');
    }

  } catch (error) {
    console.error('Error updating project stage:', error);
    alert('Failed to update project stage. Please try again.');
    return { success: false, error: error.message };
  } finally {
    // Clear loading state
    variables['d1c4f527-9d4b-4ff5-b8fa-e2d13dbbda25'] = false;
  }

