try {
    // Get original stage data and form values
    const originalStage = context.component?.props?.['stageData'];
    const stageName = context.component?.variables?.['stageName'] || originalStage?.stage_name;
    const stageDescription = context.component?.variables?.['stageDescription'] || originalStage?.description;
    const estimatedDays = context.component?.variables?.['estimatedDays'] || originalStage?.estimaed_days;

    // Validate inputs
    if (!stageName || stageName.trim() === '') {
      alert('Please enter a stage name');
      return;
    }

    if (!estimatedDays || estimatedDays.trim() === '') {
      alert('Please enter estimated days');
      return;
    }

    // Prepare updated stage data
    const updatedStageData = {
      ...originalStage,
      stage_name: stageName.trim(),
      description: stageDescription?.trim() || '',
      estimaed_days: estimatedDays.trim()
    };

    // Call global function to update stage
    const result = await utilsFunctions.executeGlobalFunction['0e736b90-9e23-4e24-835a-7783ab5c31f7'](updatedStageData);

    if (result && result.success) {
      // Close popup with success
      await utilsFunctions.closePopup(context, { success: true });
    } else {
      throw new Error(result?.error || 'Failed to update stage');
    }

  } catch (error) {
    console.error('Error submitting stage changes:', error);
    alert('Failed to update stage. Please try again.');
  }

